import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useLocation, useNavigate } from 'react-router-dom';

// --- 1. ĐỊNH NGHĨA CÁC ICON SVG TÙY CHỈNH ---
const SvgWrapper = ({ children, size = 18, color = "currentColor" }) => (
    <svg 
        xmlns="http://www.w3.org/2000/svg" 
        width={size} 
        height={size} 
        viewBox="0 0 24 24" 
        fill="none" 
        stroke={color} 
        strokeWidth="2" 
        strokeLinecap="round" 
        strokeLinejoin="round"
        style={{ display: 'inline-block', verticalAlign: 'middle' }}
    >
        {children}
    </svg>
);

const IconPlus = ({ size, color }) => (
    <SvgWrapper size={size} color={color}>
        <line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line>
    </SvgWrapper>
);

const IconEdit = ({ size, color }) => (
    <SvgWrapper size={size} color={color}>
        <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path>
        <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path>
    </SvgWrapper>
);

const IconTrash = ({ size, color }) => (
    <SvgWrapper size={size} color={color}>
        <polyline points="3 6 5 6 21 6"></polyline>
        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
    </SvgWrapper>
);

const IconCar = ({ size, color }) => (
    <SvgWrapper size={size} color={color}>
        <path d="M19 17h2c.6 0 1-.4 1-1v-3c0-.9-.7-1.7-1.5-1.9C18.7 10.6 16 10 16 10s-1.3-1.4-2.2-2.3c-.5-.4-1.1-.7-1.8-.7H5c-.6 0-1.1.4-1.4.9l-1.4 2.9A3.7 3.7 0 0 0 2 12v4c0 .6.4 1 1 1h2"></path>
        <circle cx="7" cy="17" r="2"></circle><circle cx="17" cy="17" r="2"></circle>
    </SvgWrapper>
);

// --- 2. COMPONENT CHÍNH ---
const CarManagement = () => {
    const [cars, setCars] = useState([]);
    const [showForm, setShowForm] = useState(false);
    const [editingCar, setEditingCar] = useState(null);
    const [formData, setFormData] = useState({
        name: '', brand: '', price: '', year: '',
        fuel_type: '', speed: '', image_url: '', description: ''
    });

    const location = useLocation();
    const navigate = useNavigate();

    useEffect(() => {
        fetchCars();
    }, []);

    useEffect(() => {
        if (location.state && location.state.editCarId && cars.length > 0) {
            const carToEdit = cars.find(c => c.id === location.state.editCarId);
            if (carToEdit) {
                handleEdit(carToEdit);
                navigate('/admin/cars', { replace: true, state: {} });
            }
        }
    }, [location.state, cars, navigate]);

    const fetchCars = async () => {
        try {
            const res = await axios.get('http://localhost:5000/api/cars');
            setCars(res.data.data || res.data);
        } catch (error) {
            console.error('Lỗi tải xe:', error);
        }
    };

    const handleInputChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingCar) {
                await axios.put(`http://localhost:5000/api/admin/cars/${editingCar.id}`, formData);
                alert('Cập nhật xe thành công!');
            } else {
                await axios.post('http://localhost:5000/api/admin/cars', formData);
                alert('Thêm xe thành công!');
            }
            setShowForm(false);
            setEditingCar(null);
            fetchCars();
        } catch (error) {
            alert('Lỗi: ' + (error.response?.data?.message || 'Thao tác thất bại'));
        }
    };

    const handleEdit = (car) => {
        setEditingCar(car);
        setFormData(car);
        setShowForm(true);
    };

    const handleDelete = async (id) => {
        if (window.confirm('Bạn có chắc muốn xóa xe này?')) {
            try {
                await axios.delete(`http://localhost:5000/api/admin/cars/${id}`);
                alert('Xóa xe thành công!');
                fetchCars();
            } catch (error) {
                alert('Lỗi: ' + (error.response?.data?.message || 'Xóa thất bại'));
            }
        }
    };

    return (
        <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
                <h1 style={{ display: 'flex', alignItems: 'center', gap: '12px', margin: 0 }}>
                    <IconCar size={32} color="#333" /> Quản lý xe
                </h1>
                <button 
                    onClick={() => {
                        setEditingCar(null);
                        setFormData({
                            name: '', brand: '', price: '', year: '',
                            fuel_type: '', speed: '', image_url: '', description: ''
                        });
                        setShowForm(true);
                    }}
                    style={{ 
                        padding: '10px 20px', 
                        backgroundColor: '#2563eb', 
                        color: 'white', 
                        border: 'none', 
                        borderRadius: '8px', 
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '8px',
                        fontWeight: '600'
                    }}
                >
                    <IconPlus size={18} color="white" /> Thêm xe mới
                </button>
            </div>

            {showForm && (
                <div className="modal">
                    <div className="modal-content" style={{ maxWidth: '600px', borderRadius: '12px' }}>
                        <span className="close" onClick={() => setShowForm(false)}>&times;</span>
                        <h2 style={{ marginBottom: '20px' }}>
                            {editingCar ? '📝 Sửa thông tin xe' : '🆕 Thêm xe mới'}
                        </h2>
                        
                        <form onSubmit={handleSubmit} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                            <div className="form-group" style={{ gridColumn: 'span 2' }}>
                                <label>Tên xe</label>
                                <input type="text" name="name" value={formData.name} onChange={handleInputChange} required />
                            </div>
                            <div className="form-group">
                                <label>Hãng xe</label>
                                <input type="text" name="brand" value={formData.brand} onChange={handleInputChange} required />
                            </div>
                            <div className="form-group">
                                <label>Giá (VNĐ)</label>
                                <input type="number" name="price" value={formData.price} onChange={handleInputChange} required />
                            </div>
                            <div className="form-group">
                                <label>Năm sản xuất</label>
                                <input type="number" name="year" value={formData.year} onChange={handleInputChange} required />
                            </div>
                            <div className="form-group">
                                <label>Nhiên liệu</label>
                                <select name="fuel_type" value={formData.fuel_type} onChange={handleInputChange} required>
                                    <option value="">Chọn loại</option>
                                    <option value="Xăng">Xăng</option>
                                    <option value="Dầu">Dầu</option>
                                    <option value="Hybrid">Hybrid</option>
                                    <option value="Điện">Điện</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <label>Tốc độ (km/h)</label>
                                <input type="number" name="speed" value={formData.speed} onChange={handleInputChange} required />
                            </div>
                            <div className="form-group">
                                <label>URL hình ảnh</label>
                                <input type="text" name="image_url" value={formData.image_url} onChange={handleInputChange} required />
                            </div>
                            <div className="form-group" style={{ gridColumn: 'span 2' }}>
                                <label>Mô tả</label>
                                <textarea name="description" value={formData.description} onChange={handleInputChange} rows="3" required />
                            </div>
                            <button type="submit" className="auth-btn" style={{ gridColumn: 'span 2', marginTop: '10px' }}>
                                {editingCar ? 'Lưu thay đổi' : 'Xác nhận thêm'}
                            </button>
                        </form>
                    </div>
                </div>
            )}

            <div style={{ overflowX: 'auto', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)', borderRadius: '12px' }}>
                <table className="admin-table" style={{ width: '100%', borderCollapse: 'collapse', backgroundColor: 'white' }}>
                    <thead style={{ backgroundColor: '#f8fafc' }}>
                        <tr>
                            <th style={thStyle}>Ảnh</th>
                            <th style={thStyle}>Thông tin xe</th>
                            <th style={thStyle}>Giá bán</th>
                            <th style={thStyle}>Thông số</th>
                            <th style={{ ...thStyle, textAlign: 'center' }}>Thao tác</th>
                        </tr>
                    </thead>
                    <tbody>
                        {cars.map(car => (
                            <tr key={car.id} style={{ borderBottom: '1px solid #f1f5f9' }}>
                                <td style={tdStyle}>
                                    <img 
                                        src={car.image_url} 
                                        alt={car.name}
                                        style={{ width: '80px', height: '50px', objectFit: 'cover', borderRadius: '6px' }}
                                    />
                                </td>
                                <td style={tdStyle}>
                                    <div style={{ fontWeight: 'bold', fontSize: '15px' }}>{car.name}</div>
                                    <div style={{ fontSize: '12px', color: '#64748b' }}>Hãng: {car.brand}</div>
                                </td>
                                <td style={tdStyle}>
                                    <div style={{ color: '#059669', fontWeight: 'bold' }}>
                                        {car.price?.toLocaleString('vi-VN')} ₫
                                    </div>
                                </td>
                                <td style={tdStyle}>
                                    <div style={{ fontSize: '13px' }}>📅 {car.year}</div>
                                    <div style={{ fontSize: '13px' }}>⛽ {car.fuel_type}</div>
                                </td>
                                <td style={{ ...tdStyle, textAlign: 'center' }}>
                                    <div style={{ display: 'flex', justifyContent: 'center', gap: '10px' }}>
                                        <button onClick={() => handleEdit(car)} title="Sửa" style={actionBtnStyle}>
                                            <IconEdit size={18} color="#2563eb" />
                                        </button>
                                        <button onClick={() => handleDelete(car.id)} title="Xóa" style={actionBtnStyle}>
                                            <IconTrash size={18} color="#ef4444" />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

// --- STYLES ---
const thStyle = { padding: '15px', textAlign: 'left', color: '#475569', fontSize: '14px', fontWeight: '600' };
const tdStyle = { padding: '15px', verticalAlign: 'middle' };
const actionBtnStyle = { 
    background: 'none', 
    border: '1px solid #e2e8f0', 
    padding: '6px', 
    borderRadius: '6px', 
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    transition: '0.2s'
};

export default CarManagement;
